activeInventoryProductCreate.query:
mutation LocationDeleteInventoryProductCreate($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product {
        id
        title
        variants(first: 1) {
          nodes {
            id
            inventoryItem {
              id
              tracked
              requiresShipping
            }
          }
        }
      }
      userErrors {
        field
        message
      }
    }
  }

activeInventoryProductTrack.query:
mutation LocationDeleteInventoryProductTrack($productId: ID!, $variants: [ProductVariantsBulkInput!]!) {
    productVariantsBulkUpdate(productId: $productId, variants: $variants) {
      product {
        id
        tracksInventory
        totalInventory
      }
      productVariants {
        id
        inventoryItem {
          id
          tracked
          requiresShipping
        }
      }
      userErrors {
        field
        message
      }
    }
  }

activeInventoryActivate.query:
mutation LocationDeleteInventoryActivate(
    $inventoryItemId: ID!
    $locationId: ID!
    $available: Int
    $idempotencyKey: String!
  ) {
    inventoryActivate(
      inventoryItemId: $inventoryItemId
      locationId: $locationId
      available: $available
    ) @idempotent(key: $idempotencyKey) {
      inventoryLevel {
        id
        location {
          id
          name
        }
        quantities(names: ["available", "committed", "on_hand"]) {
          name
          quantity
          updatedAt
        }
      }
      userErrors {
        field
        message
      }
    }
  }

fulfillmentServiceCreate.query:
mutation LocationDeleteFulfillmentServiceCreate($name: String!) {
    fulfillmentServiceCreate(
      name: $name
      trackingSupport: true
      inventoryManagement: true
      requiresShippingMethod: true
    ) {
      fulfillmentService {
        id
        handle
        serviceName
        location {
          id
          name
          isFulfillmentService
          isActive
        }
      }
      userErrors {
        field
        message
      }
    }
  }

